const client = $input.first().json.fields;
const clientName = client.ClientName || 'there';
const lastVisit = client.LastVisitDate || '';
const salonName = process.env.SALON_NAME || 'our salon';
const salonPhone = process.env.SALON_PHONE || '';

// Calculate days since last visit
const lastVisitDate = new Date(lastVisit);
const today = new Date();
const daysSince = Math.floor((today - lastVisitDate) / (1000 * 60 * 60 * 24));

let message, tier;

if (daysSince >= 30 && daysSince < 65) {
  tier = '30-day';
  message = `Hi ${clientName}! 💅 It's been a while since your last visit to ${salonName}! We miss you! Book this week and get $5 off your next service. Reply BOOK or call ${salonPhone} 🌸`;
} else if (daysSince >= 60 && daysSince < 95) {
  tier = '60-day';
  message = `Hi ${clientName}! 💅 We haven't seen you in 2 months at ${salonName} — we hope you're doing great! Come back this month and enjoy 10% off. Reply BOOK to schedule! 🌸`;
} else if (daysSince >= 90) {
  tier = '90-day';
  message = `Hi ${clientName}! 🌸 We miss you at ${salonName}! It's been 3 months since your last visit. As a valued client, here's a special: FREE nail art with any full-price service. Valid this week only! Reply BOOK or call ${salonPhone}.`;
}

return [{ json: {
  phone: client.Phone,
  message,
  clientId: $input.first().json.id,
  clientName,
  tier,
  daysSince
}}];
